import math

class GameState:
    def __init__(self):
        self.player_pos = [0, 0]
        self.player_health = 100
        self.score = 0
        self.entities = []

    def to_json(self):
        return json.dumps(self.__dict__)

    @classmethod
    def from_json(cls, data):
        state = cls()
        params = json.loads(data)
        state.__dict__.update(params)
        return state

class CollisionSystem:
    @staticmethod
    def check_aabb_collision(rect1, rect2):
        """Axis-Aligned Bounding Box collision detection"""
        return (
            rect1['x'] < rect2['x'] + rect2['w'] and
            rect1['x'] + rect1['w'] > rect2['x'] and
            rect1['y'] < rect2['y'] + rect2['h'] and
            rect1['y'] + rect1['h'] > rect2['y']
        )

    @staticmethod
    def resolve_collision(entity, obstacle):
        """Prevents clipping by snapping entity to obstacle boundary"""
        # Calculate overlap on both axes
        overlap_x = min(entity.rect['x'] + entity.rect['w'], obstacle.rect['x'] + obstacle.rect['w']) - max(entity.rect['x'], obstacle.rect['x'])
        overlap_y = min(entity.rect['y'] + entity.rect['h'], obstacle.rect['y'] + obstacle.rect['h']) - max(entity.rect['y'], obstacle.rect['y'])

        if overlap_x < overlap_y:
            if entity.vx > 0: entity.x -= overlap_x
            elif entity.vx < 0: entity.x += overlap_x
        else:
            if entity.vy > 0: entity.y -= overlap_y
            elif entity.vy < 0: entity.y += overlap_y

class EnemyAI:
    def __init__(self, entity):
        self.entity = entity
        self.speed = 2.0

    def update(self, player_pos):
        # Vectorized movement towards player
        dx = player_pos[0] - self.entity.x
        dy = player_pos[1] - self.entity.y
        dist = math.hypot(dx, dy)

        if dist > 0:
            self.entity.vx = (dx / dist) * self.speed
            self.entity.vy = (dy / dist) * self.speed
        else:
            self.entity.vx = 0
            self.entity.vy = 0

class GameEngine:
    def __init__(self):
        self.state = GameState()
        self.collisions = CollisionSystem()

    def save_game(self, filename="savegame.json"):
        try:
            with open(filename, 'w') as f:
                f.write(self.state.to_json())
            return True
        except IOError as e:
            print(f"Save failed: {e}")
            return False

    def load_game(self, filename="savegame.json"):
        try:
            with open(filename, 'r') as f:
                self.state = GameState.from_json(f.read())
            return True
        except (IOError, json.JSONDecodeError) as e:
            print(f"Load failed: {e}")
            return False

    def update_physics(self, entities, obstacles):
        for entity in entities:
            # Apply movement
            entity.x += entity.vx
            entity.y += entity.vy

            # Check and resolve collisions with static obstacles
            for obs in obstacles:
                if self.collisions.check_aabb_collision(entity.rect, obs.rect):
